#!/usr/bin/env python3
"""
Generate vendor/pcre2_embed.h — a single-header amalgamation of the minimal
PCRE2 10.42 subset.

Run from the repository root after cloning PCRE2 10.42 into a local directory:

  git clone --depth=1 --branch pcre2-10.42 \\
      https://github.com/PCRE2Project/pcre2.git /tmp/pcre2-src
  # Build the generated pcre2_chartables.c (requires cmake):
  cd /tmp/pcre2-src && mkdir cmake_build && cd cmake_build && \\
      cmake .. -DPCRE2_BUILD_TESTS=OFF && \\
      cmake --build . --target pcre2_chartables 2>/dev/null; true
  # Run from repo root:
  python3 vendor/tools/amalgamate_pcre2.py \\
      --src /tmp/pcre2-src/src \\
      --chartables /tmp/pcre2-src/cmake_build/pcre2_chartables.c \\
      --out vendor/pcre2_embed.h

Usage (STB style):
  // In exactly ONE translation unit:
  #define PCRE2_EMBED_IMPLEMENTATION
  #include "vendor/pcre2_embed.h"

  // In all other files (public API only):
  #include "vendor/pcre2_embed.h"
"""
import argparse, os, re, sys

def parse_args():
    p = argparse.ArgumentParser(
        description="Amalgamate a minimal PCRE2 subset into a single header.")
    p.add_argument("--src",
        default=os.path.join(os.path.dirname(__file__), "../../..", "pcre2-src", "src"),
        help="Path to the PCRE2 src/ directory (default: ../../../pcre2-src/src)")
    p.add_argument("--chartables",
        default=None,
        help="Path to pre-generated pcre2_chartables.c "
             "(default: <src>/../cmake_build/pcre2_chartables.c)")
    p.add_argument("--out",
        default=os.path.join(os.path.dirname(__file__), "..", "pcre2_embed.h"),
        help="Output file path (default: vendor/pcre2_embed.h next to this script)")
    return p.parse_args()

def main():
    args = parse_args()
    src_dir   = os.path.realpath(args.src)
    out_path  = os.path.realpath(args.out)

    if args.chartables:
        chartables = os.path.realpath(args.chartables)
    else:
        chartables = os.path.realpath(
            os.path.join(src_dir, "..", "cmake_build", "pcre2_chartables.c"))

    if not os.path.isdir(src_dir):
        sys.exit(f"ERROR: PCRE2 src directory not found: {src_dir}\n"
                 "  Clone PCRE2 10.42 and pass --src /path/to/pcre2/src")
    if not os.path.isfile(chartables):
        sys.exit(f"ERROR: pcre2_chartables.c not found: {chartables}\n"
                 "  Build PCRE2 with cmake to generate it, or pass --chartables")

    # ── Virtual file-system: merge src_dir + one override ─────────────────────
    # cmake_build dir: for files that cmake generates (pcre2.h, pcre2_chartables.c)
    cmake_build_dir = os.path.dirname(chartables)

    def read(name):
        # Use the pre-built chartables.c override
        if name == "pcre2_chartables.c":
            path = chartables
        else:
            # Some files (e.g. pcre2.h) are generated by cmake into cmake_build/
            cmake_path = os.path.join(cmake_build_dir, name)
            src_path   = os.path.join(src_dir, name)
            path = cmake_path if os.path.isfile(cmake_path) else src_path
        if not os.path.isfile(path):
            return None
        with open(path) as f:
            return f.read()

    # ── Files to strip from .c files (already emitted in the impl preamble) ──
    STRIP_INCLUDES = {
        '"config.h"',
        '"pcre2_internal.h"',
    }

    # ── Files that are #included BY a parent file, not standalone TUs ─────────
    INCLUDED_BY_PARENT = {
        "pcre2_jit_match.c",
        "pcre2_jit_misc.c",
        "pcre2_ucptables.c",   # inside #ifdef SUPPORT_UNICODE (dead)
        "pcre2_printint.c",    # inside #if 0 (dead)
    }

    # ── Internal headers that pcre2_internal.h includes ───────────────────────
    INTERNAL_HEADERS = {
        "pcre2.h",
        "pcre2_ucp.h",
        "pcre2_intmodedep.h",
        "pcre2_jit_neon_inc.h",
        "pcre2_jit_simd_inc.h",
    }

    emitted = set()

    def banner(name, char="─"):
        w = 74
        title = f" {name} "
        side = (w - len(title)) // 2
        return f"/* {char * side}{title}{char * (w - side - len(title))} */\n"

    def emit_file(name, depth=0):
        if name in emitted:
            return f"/* (already inlined: {name}) */\n"
        emitted.add(name)

        raw = read(name)
        if raw is None:
            return f"/* FILE NOT FOUND: {name} */\n"

        lines = raw.split('\n')
        out = [banner(name)]

        for line in lines:
            stripped = line.strip()
            m = re.match(r'\s*#\s*include\s*("(?:[^"]+)")', stripped)
            if m:
                inc_token = m.group(1)
                inc_name  = inc_token[1:-1]

                if inc_token in STRIP_INCLUDES:
                    out.append(f"/* amalgamated – stripped: #include {inc_token} */\n")
                    continue

                if (inc_name in INTERNAL_HEADERS or
                        inc_name in INCLUDED_BY_PARENT):
                    if read(inc_name) is not None:
                        out.append(f"\n/* >>>>>> begin inline: {inc_name} */\n")
                        out.append(emit_file(inc_name, depth + 1))
                        out.append(f"/* <<<<<< end inline:  {inc_name} */\n\n")
                        continue

            out.append(line + '\n')

        return ''.join(out)

    # ── Compilation order for the .c files ────────────────────────────────────
    C_FILES_ORDER = [
        "pcre2_chartables.c",
        "pcre2_tables.c",
        "pcre2_ucd.c",
        "pcre2_string_utils.c",
        "pcre2_error.c",
        "pcre2_context.c",
        "pcre2_maketables.c",
        "pcre2_valid_utf.c",
        "pcre2_ord2utf.c",
        "pcre2_newline.c",
        "pcre2_find_bracket.c",
        "pcre2_xclass.c",
        "pcre2_auto_possess.c",
        "pcre2_script_run.c",
        "pcre2_study.c",
        "pcre2_compile.c",
        "pcre2_match_data.c",
        "pcre2_match.c",
        "pcre2_pattern_info.c",
        "pcre2_substring.c",
        "pcre2_substitute.c",
        "pcre2_jit_compile.c",
    ]

    # ── Build the amalgamation ─────────────────────────────────────────────────
    sections = []

    sections.append("""\
/*
 * pcre2_embed.h  –  Amalgamated PCRE2 10.42 for asciiquack
 *
 * A minimal, self-contained single-header copy of the PCRE2 10.42 regex
 * library.  Only the 8-bit NFA interpreter is included; JIT, DFA, Unicode
 * property tables (\\p{}), serialization, POSIX wrapper, and the tool
 * programs are intentionally omitted.
 *
 * ── Usage ──────────────────────────────────────────────────────────────────
 *
 *   Include in every translation unit that needs the API:
 *
 *     #include "vendor/pcre2_embed.h"
 *
 *   In EXACTLY ONE translation unit (e.g. vendor/pcre2_impl.c), before the
 *   #include, define the implementation macro:
 *
 *     #define PCRE2_EMBED_IMPLEMENTATION
 *     #include "vendor/pcre2_embed.h"
 *
 * ── Licence ────────────────────────────────────────────────────────────────
 *
 *   PCRE2 is distributed under the BSD licence.
 *   Copyright (c) 2016-2022 University of Cambridge.
 *   See the copyright notice at the top of each inlined source section.
 *
 * ── Source ─────────────────────────────────────────────────────────────────
 *
 *   PCRE2 10.42 – https://github.com/PCRE2Project/pcre2
 *   Generated by vendor/tools/amalgamate_pcre2.py
 *   (run from the repository root after cloning PCRE2 10.42 into /tmp/pcre2-src)
 */

#ifndef PCRE2_EMBED_H
#define PCRE2_EMBED_H

/* Always make the 8-bit API available; tell the library we're a static
 * build so it doesn't try to use dllexport/dllimport on Windows. */
#ifndef PCRE2_CODE_UNIT_WIDTH
#  define PCRE2_CODE_UNIT_WIDTH 8
#endif
#ifndef PCRE2_STATIC
#  define PCRE2_STATIC
#endif

""")

    # Public API
    sections.append("/* ═══════════════════ PUBLIC API (pcre2.h) ═══════════════════════════════ */\n\n")
    emitted.add("pcre2.h")
    sections.append(read("pcre2.h") + "\n\n")

    # Implementation section
    sections.append("""
/* ═══════════════════════════════════════════════════════════════════════════
 * IMPLEMENTATION  (compiled in exactly one translation unit)
 * ═══════════════════════════════════════════════════════════════════════════ */
#ifdef PCRE2_EMBED_IMPLEMENTATION
#ifndef PCRE2_EMBED_IMPLEMENTATION_DONE
#define PCRE2_EMBED_IMPLEMENTATION_DONE

#ifdef __cplusplus
extern "C" {
#endif

""")

    # Minimal config.h
    sections.append("/* ── Embedded config.h ──────────────────────────────────────────────────── */\n")
    sections.append("""\
/* Minimal build configuration: 8-bit mode, no JIT, no Unicode properties. */
#ifndef PCRE2_EMBED_CONFIG_H
#define PCRE2_EMBED_CONFIG_H
#define SUPPORT_PCRE2_8 1
/* #undef SUPPORT_JIT */
/* #undef SUPPORT_UNICODE */
#define HAVE_BCOPY 1
#define HAVE_MEMMOVE 1
#define HAVE_STRERROR 1
#define LINK_SIZE            2
#define HEAP_LIMIT           20000000
#define MATCH_LIMIT          10000000
#define MATCH_LIMIT_DEPTH    MATCH_LIMIT
#define NEWLINE_DEFAULT      2
#define PARENS_NEST_LIMIT    250
#define MAX_NAME_SIZE        32
#define MAX_NAME_COUNT       10000
#endif /* PCRE2_EMBED_CONFIG_H */

""")

    # PCRE2_EXP_DEFN fix
    sections.append("""\
/* PCRE2_EXP_DEFN is defined inside `#ifndef PCRE2_EXP_DECL` in
 * pcre2_internal.h, but pcre2.h (emitted above) already defines PCRE2_EXP_DECL,
 * so that block is skipped.  For a static build PCRE2_EXP_DEFN is empty. */
#ifndef PCRE2_EXP_DEFN
#  define PCRE2_EXP_DEFN
#endif

""")

    # Internal headers
    sections.append("/* ── Internal headers ───────────────────────────────────────────────────── */\n")
    emitted.add("pcre2_ucp.h")
    sections.append(read("pcre2_ucp.h") + "\n\n")
    sections.append(emit_file("pcre2_internal.h"))
    sections.append("\n")

    # .c files
    sections.append("\n/* ═══════════════════ IMPLEMENTATION FILES ═══════════════════════════════ */\n\n")
    for fname in C_FILES_ORDER:
        sections.append(emit_file(fname))
        sections.append("\n")

    sections.append("""
#ifdef __cplusplus
}  /* extern "C" */
#endif

#endif /* PCRE2_EMBED_IMPLEMENTATION_DONE */
#endif /* PCRE2_EMBED_IMPLEMENTATION */

#endif /* PCRE2_EMBED_H */
""")

    result = ''.join(sections)
    os.makedirs(os.path.dirname(out_path), exist_ok=True)
    with open(out_path, 'w') as f:
        f.write(result)

    lines = result.count('\n')
    print(f"Written {out_path}")
    print(f"Total lines: {lines:,}")

if __name__ == "__main__":
    main()
